for p in products:
    content = f"{p['nameTh']}\n\nหมวดหมู่: {p['cat']}\n\n"
    content += f"คุณสมบัติ:\n" + "\n".join(f"- {f}" for f in p["features"]) + "\n\n"
    content += f"ผลประโยชน์:\n" + "\n".join(f"- {b}" for b in p["benefits"]) + "\n\n"
    content += f"คุณสมบัติผู้สมัคร: {p['elig']}\n\nเบี้ยประกัน: {p['price']}"
    add(p["name"], content, "product", p["url"])

